    const handlers = {
      fetchAsset: async () =>
        new Response("<svg></svg>", {
          status: 200,
          headers: { "Content-Type": "image/svg+xml" },
        }),
    };
    const response = await handleImageOptimization(request, handlers, undefined, {
      dangerouslyAllowSVG: false,
    });
